import{_ as e,o as a,c as n,ag as s}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"Database Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"theory/databases/database-concepts.md","filePath":"theory/databases/database-concepts.md"}'),r={name:"theory/databases/database-concepts.md"};function d(o,t,i,l,c,p){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="database-concepts" tabindex="-1">Database Concepts <a class="header-anchor" href="#database-concepts" aria-label="Permalink to &quot;Database Concepts&quot;">​</a></h1><p>A spreadsheet stores data in rows and columns — so does a database. But a database goes further: it enforces rules, prevents duplicates, links related data across multiple tables, and lets you query millions of records in milliseconds. Understanding database concepts is essential for both Paper 1 (SQL) and Paper 2 (theory).</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11+</p><p>Database concepts are introduced in Grade 11. Normalisation and complex queries extend into Grade 12.</p></div><hr><h2 id="data-vs-information-vs-knowledge" tabindex="-1">Data vs Information vs Knowledge <a class="header-anchor" href="#data-vs-information-vs-knowledge" aria-label="Permalink to &quot;Data vs Information vs Knowledge&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Data</th><th>Information</th><th>Knowledge</th></tr></thead><tbody><tr><td><strong>Definition</strong></td><td>Raw, unprocessed facts</td><td>Data processed into meaningful context</td><td>Information understood and applied</td></tr><tr><td><strong>Example</strong></td><td><code>87</code>, <code>Ayden</code>, <code>2024-03-15</code></td><td>&quot;Ayden scored 87% on the March 2024 test&quot;</td><td>&quot;Ayden consistently scores high in programming — recommend advanced class&quot;</td></tr><tr><td><strong>Useful?</strong></td><td>Not on its own</td><td>Yes</td><td>Actionable</td></tr></tbody></table><hr><h2 id="what-is-a-database" tabindex="-1">What is a Database? <a class="header-anchor" href="#what-is-a-database" aria-label="Permalink to &quot;What is a Database?&quot;">​</a></h2><p>A <strong>database</strong> is an organised collection of related data stored so it can be easily accessed, managed, and updated.</p><p>A <strong>Database Management System (DBMS)</strong> is the software that manages the database — it handles storing, retrieving, querying, and securing data.</p><p><strong>Examples of DBMS software:</strong></p><table tabindex="0"><thead><tr><th>DBMS</th><th>Type</th><th>Use</th></tr></thead><tbody><tr><td>Microsoft Access</td><td>Desktop DBMS</td><td>Small databases, learning, small businesses</td></tr><tr><td>MySQL</td><td>Server DBMS (free, open source)</td><td>Websites, web apps</td></tr><tr><td>PostgreSQL</td><td>Server DBMS (free, open source)</td><td>Enterprise applications</td></tr><tr><td>Microsoft SQL Server</td><td>Enterprise DBMS</td><td>Large organisations, Microsoft ecosystem</td></tr><tr><td>Oracle</td><td>Enterprise DBMS</td><td>Banking, large corporations</td></tr><tr><td>SQLite</td><td>Embedded DBMS</td><td>Mobile apps, local storage</td></tr></tbody></table><hr><h2 id="database-terminology" tabindex="-1">Database Terminology <a class="header-anchor" href="#database-terminology" aria-label="Permalink to &quot;Database Terminology&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th><th>Example</th></tr></thead><tbody><tr><td><strong>Table (Relation)</strong></td><td>A grid of rows and columns storing data about one entity</td><td><code>Students</code> table</td></tr><tr><td><strong>Field (Column / Attribute)</strong></td><td>A single category of data</td><td><code>Surname</code>, <code>Mark</code>, <code>Grade</code></td></tr><tr><td><strong>Record (Row / Tuple)</strong></td><td>One complete set of related field values</td><td>One student&#39;s data</td></tr><tr><td><strong>Primary Key (PK)</strong></td><td>A field that uniquely identifies each record — no duplicates, no NULL</td><td><code>StudentID</code></td></tr><tr><td><strong>Foreign Key (FK)</strong></td><td>A field in one table that references the PK of another table — creates a link</td><td><code>SubjectID</code> in <code>Marks</code> table, referencing <code>Subjects</code> table</td></tr><tr><td><strong>Data type</strong></td><td>Specifies what kind of data a field holds</td><td>Integer, Text, Date, Boolean</td></tr></tbody></table><p><strong>Visualising the terms:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Table: Students</span></span>
<span class="line"><span>┌──────────────┬──────────┬───────────┬───────┬──────┐</span></span>
<span class="line"><span>│  StudentID   │ Surname  │ FirstName │ Grade │ Mark │  ← Fields (columns)</span></span>
<span class="line"><span>├──────────────┼──────────┼───────────┼───────┼──────┤</span></span>
<span class="line"><span>│    1001      │  Adams   │   Alice   │  11   │  87  │  ← Record (row)</span></span>
<span class="line"><span>│    1002      │  Botha   │    Ben    │  11   │  72  │</span></span>
<span class="line"><span>│    1003      │ Coetzee  │  Carol    │  12   │  91  │</span></span>
<span class="line"><span>└──────────────┴──────────┴───────────┴───────┴──────┘</span></span>
<span class="line"><span>      ↑</span></span>
<span class="line"><span>  Primary Key (unique)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><hr><h2 id="primary-key-pk" tabindex="-1">Primary Key (PK) <a class="header-anchor" href="#primary-key-pk" aria-label="Permalink to &quot;Primary Key (PK)&quot;">​</a></h2><p>A <strong>primary key</strong> is a field (or combination of fields) that:</p><ul><li><strong>Uniquely identifies</strong> each record</li><li><strong>Cannot be NULL</strong> (empty)</li><li><strong>Cannot be duplicated</strong> — no two records can have the same PK value</li></ul><p><strong>Examples of good PKs:</strong></p><ul><li><code>StudentID</code> (auto-generated number)</li><li><code>IDNumber</code> (SA 13-digit ID — unique per person)</li><li><code>ISBN</code> (book identifier)</li><li><code>VehicleRegistration</code> (unique per vehicle)</li></ul><p><strong>Natural vs Surrogate Keys:</strong></p><ul><li><strong>Natural key</strong>: A field that exists naturally and is inherently unique (ID number, ISBN)</li><li><strong>Surrogate key</strong>: An artificial ID created specifically to be the PK (auto-increment integer like <code>StudentID = 1001</code>)</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">When in Doubt, Use Surrogate Keys</p><p>Auto-increment integers are reliable PKs. Natural keys can have exceptions (a person can change their ID number, a product barcode can be reprinted). Surrogate keys never change.</p></div><hr><h2 id="foreign-key-fk-—-linking-tables" tabindex="-1">Foreign Key (FK) — Linking Tables <a class="header-anchor" href="#foreign-key-fk-—-linking-tables" aria-label="Permalink to &quot;Foreign Key (FK) — Linking Tables&quot;">​</a></h2><p>A <strong>foreign key</strong> is a field in one table that holds the primary key value from another table. This is how relational databases <strong>link</strong> related data without storing duplicates.</p><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Table: Students           Table: Marks</span></span>
<span class="line"><span>┌──────────┬─────────┐    ┌──────────┬───────────┬──────┐</span></span>
<span class="line"><span>│StudentID │ Surname │    │MarkID    │ StudentID │ Mark │</span></span>
<span class="line"><span>├──────────┼─────────┤    ├──────────┼───────────┼──────┤</span></span>
<span class="line"><span>│ 1001     │ Adams   │    │ 1        │ 1001      │  87  │</span></span>
<span class="line"><span>│ 1002     │ Botha   │    │ 2        │ 1001      │  92  │</span></span>
<span class="line"><span>└──────────┴─────────┘    │ 3        │ 1002      │  75  │</span></span>
<span class="line"><span>                          └──────────┴───────────┴──────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><code>Marks.StudentID</code> is a <strong>foreign key</strong> referencing <code>Students.StudentID</code>. This link lets you combine data from both tables in a query (using JOIN).</p><hr><h2 id="relationships-between-tables" tabindex="-1">Relationships Between Tables <a class="header-anchor" href="#relationships-between-tables" aria-label="Permalink to &quot;Relationships Between Tables&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Relationship</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><strong>One-to-One (1:1)</strong></td><td>One record in A matches exactly one record in B</td><td>One student has one locker</td></tr><tr><td><strong>One-to-Many (1:M)</strong></td><td>One record in A matches many records in B</td><td>One student has many marks</td></tr><tr><td><strong>Many-to-Many (M:M)</strong></td><td>Many records in A match many in B</td><td>Students enrolled in many subjects; subjects have many students</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Many-to-Many Requires a Junction Table</p><p>You cannot directly implement M:M in a relational database. You need a <strong>junction table</strong> (also called a bridge or linking table) that holds the FKs from both sides.</p></div><p><strong>Example: Students ↔ Subjects (many-to-many)</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Students table  →  Enrolment table  →  Subjects table</span></span>
<span class="line"><span>(StudentID PK)     (StudentID FK,      (SubjectID PK)</span></span>
<span class="line"><span>                    SubjectID FK)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="data-integrity" tabindex="-1">Data Integrity <a class="header-anchor" href="#data-integrity" aria-label="Permalink to &quot;Data Integrity&quot;">​</a></h2><p><strong>Data integrity</strong> means the data is accurate, consistent, and valid. A good DBMS enforces integrity automatically.</p><table tabindex="0"><thead><tr><th>Type</th><th>What it enforces</th><th>Example</th></tr></thead><tbody><tr><td><strong>Entity integrity</strong></td><td>PK is unique and not NULL</td><td>No two students with same StudentID</td></tr><tr><td><strong>Referential integrity</strong></td><td>FK must match an existing PK</td><td>Can&#39;t assign a mark to a non-existent student</td></tr><tr><td><strong>Domain integrity</strong></td><td>Values must match the field&#39;s data type and rules</td><td>Mark must be 0–100 (Integer); not &quot;eighty&quot;</td></tr><tr><td><strong>User-defined integrity</strong></td><td>Custom business rules</td><td>Grade must be 10, 11, or 12</td></tr></tbody></table><hr><h2 id="data-validation-vs-verification" tabindex="-1">Data Validation vs Verification <a class="header-anchor" href="#data-validation-vs-verification" aria-label="Permalink to &quot;Data Validation vs Verification&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Validation</th><th>Verification</th></tr></thead><tbody><tr><td><strong>Definition</strong></td><td>Checking that data matches predefined rules</td><td>Checking that data was entered correctly (matches the source)</td></tr><tr><td><strong>Who does it?</strong></td><td>The computer/DBMS</td><td>The human or a double-entry system</td></tr><tr><td><strong>Catches</strong></td><td>Wrong type, out of range, wrong format</td><td>Transcription errors (user typed wrong thing)</td></tr><tr><td><strong>Examples</strong></td><td>Mark must be 0–100; Date must be valid</td><td>Enter password twice; print receipt for user to check</td></tr></tbody></table><h3 id="validation-types" tabindex="-1">Validation Types <a class="header-anchor" href="#validation-types" aria-label="Permalink to &quot;Validation Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Presence check</strong></td><td>Field cannot be left empty</td><td>Surname must be filled in</td></tr><tr><td><strong>Type check</strong></td><td>Data must be the correct data type</td><td>Mark must be Integer, not Text</td></tr><tr><td><strong>Range check</strong></td><td>Value must be within min–max</td><td>Mark: 0 ≤ mark ≤ 100</td></tr><tr><td><strong>Length check</strong></td><td>String must be within min/max length</td><td>ID number must be exactly 13 digits</td></tr><tr><td><strong>Format check</strong></td><td>Data must match a pattern</td><td>Email must contain @ and .</td></tr><tr><td><strong>Lookup check</strong></td><td>Value must match a value in a list</td><td>Province must be one of 9 provinces</td></tr><tr><td><strong>Check digit</strong></td><td>Calculated digit validates the whole number</td><td>Barcode last digit, ISBN last digit</td></tr><tr><td><strong>Consistency check</strong></td><td>Two fields must be logically consistent</td><td>End date must be after start date</td></tr></tbody></table><hr><h2 id="database-advantages-over-spreadsheets" tabindex="-1">Database Advantages over Spreadsheets <a class="header-anchor" href="#database-advantages-over-spreadsheets" aria-label="Permalink to &quot;Database Advantages over Spreadsheets&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Spreadsheet</th><th>Database</th></tr></thead><tbody><tr><td>Duplicate control</td><td>Manual</td><td>Automatic (PK constraint)</td></tr><tr><td>Multi-user access</td><td>Difficult (file locking)</td><td>Designed for it</td></tr><tr><td>Data relationships</td><td>No built-in links</td><td>Enforced via FK</td></tr><tr><td>Querying</td><td>Limited</td><td>Powerful SQL</td></tr><tr><td>Security</td><td>File-level</td><td>Field/record/user-level</td></tr><tr><td>Data volume</td><td>Millions of rows (practical limit)</td><td>Billions of records</td></tr><tr><td>Data integrity</td><td>No enforcement</td><td>Enforced by DBMS</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>DBMS</strong></td><td>Database Management System — software managing the database</td></tr><tr><td><strong>Table</strong></td><td>Grid of rows and columns for one entity</td></tr><tr><td><strong>Field</strong></td><td>One column/attribute in a table</td></tr><tr><td><strong>Record</strong></td><td>One row of data in a table</td></tr><tr><td><strong>Primary key</strong></td><td>Field uniquely identifying each record</td></tr><tr><td><strong>Foreign key</strong></td><td>Field referencing the PK of another table</td></tr><tr><td><strong>Relationship</strong></td><td>Link between tables via PK-FK</td></tr><tr><td><strong>Data integrity</strong></td><td>Accuracy and consistency of data</td></tr><tr><td><strong>Validation</strong></td><td>Automatic rule-checking by the system</td></tr><tr><td><strong>Verification</strong></td><td>Human-check that data was entered correctly</td></tr><tr><td><strong>Entity integrity</strong></td><td>No NULL or duplicate PKs</td></tr><tr><td><strong>Referential integrity</strong></td><td>FK must reference an existing PK</td></tr><tr><td><strong>Junction table</strong></td><td>Bridge table implementing M:M relationships</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is a primary key? Give an example.&quot;</strong> — unique, not null, identifies each record; <code>StudentID</code></p></li><li><p><strong>&quot;What is a foreign key and what is its purpose?&quot;</strong> — field referencing another table&#39;s PK; creates a relationship between tables</p></li><li><p><strong>&quot;Give THREE types of validation and explain each&quot;</strong> — presence, range, type, length, format — always explain what the rule checks</p></li><li><p><strong>&quot;Explain the difference between validation and verification&quot;</strong> — validation = system checks rules; verification = human confirms correct data entry</p></li><li><p><strong>&quot;Give ONE advantage of a database over a spreadsheet&quot;</strong> — referential integrity, multi-user access, better querying, automatic duplicate prevention</p></li></ol></div>`,56)])])}const b=e(r,[["render",d]]);export{u as __pageData,b as default};
